99	          let execStartTime: number | undefined;
100	
101	          // Create store eagerly; ALS is seeded in beforeMemoization for user code.
102	          // Hooks access store via closure (see architecture note above).
103	          const store = createStore(
104	            alsContext as { requestId: string } & Record<string, unknown>
105	          );
106	
107	          /** Push a journal entry directly to the store (bypasses ALS). */
108	          function journal(
109	            level: JournalEntry["level"],
110	            msg: string,
111	            meta?: Record<string, unknown>
112	          ) {
113	            if (store.journal.length < MAX_JOURNAL_ENTRIES) {
114	              store.journal.push({ ts: Date.now(), level, msg, meta });
115	            }
116	          }
117	
118	          journal("info", "function:start");
119	
120	          // Wrap in Sentry isolation scope (synchronous — matches sentryMiddleware)
121	          return withIsolationScope((scope) => {
122	            scope.setTag("inngest.function.id", fnId);
123	            scope.setTag("inngest.run.id", ctx.runId);
124	            if (ctx.event?.name) {
125	              scope.setTag("inngest.event.name", ctx.event.name);
126	            }
127	
128	            // startSpanManual: span lives until explicit .end() in beforeResponse
129	            return startSpanManual(
130	              {
131	                name: `inngest/${fnId}`,
132	                op: "function.inngest",
133	                attributes: {
134	                  [SEMANTIC_ATTRIBUTE_SENTRY_SOURCE]: "route",
135	                  [SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN]:
136	                    "auto.function.inngest.middleware",
137	                  "inngest.run.id": ctx.runId,
138	                  "inngest.event.name": ctx.event?.name ?? "unknown",
139	                },
140	                scope,
141	              },
142	              (reqSpan) => {
143	                // Add Sentry trace ID to store for log correlation
144	                const traceId = reqSpan.spanContext().traceId;
145	                if (traceId) {
146	                  store.ctx = { ...store.ctx, traceId };
147	                }
148	
149	                return {
150	                  // Seed ALS for user function code. enterWith may not propagate
151	                  // to hooks (due to waterfall/cacheFn promise chains) but it
152	                  // DOES propagate to the user function executed via runAsPromise.
153	                  beforeMemoization() {
154	                    requestStore.enterWith(store);
155	                  },
156	
157	                  beforeExecution() {
158	                    execStartTime = Date.now();
159	                    journal("info", "execution:start");
160	                  },
161	
162	                  afterExecution() {
163	                    const execMs = execStartTime
